+/**
+ * Audit logging service for notifications.
+ *
+ * Records every notification dispatched through the system. Listens to
+ * notification:send events on the EventBus and creates an audit trail.
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type { NotificationPriority, NotificationSendEvent } from '../events/event-types.js';
+
+export interface AuditEntry {
+  id: string;
+  timestamp: Date;
+  channel: string;
+  priority: NotificationPriority;
+  recipient: string;
+  subject: string;
+}
+
+let nextAuditId = 1;
+
+function generateAuditId(): string {
+  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
+}
+
+export function resetAuditIdCounter(): void {
+  nextAuditId = 1;
+}
+
+export class AuditService {
+  private entries: AuditEntry[] = [];
+
+  constructor(private eventBus: EventBus) {
+    this.eventBus.on<NotificationSendEvent>('notification:send', (event) => {
+      this.record(event);
+    });
+  }
+
+  private record(event: NotificationSendEvent): void {
+    this.entries.push({
+      id: generateAuditId(),
+      timestamp: event.timestamp,
+      channel: event.channel,
+      priority: event.priority,
+      recipient: event.recipient,
+      subject: event.subject,
+    });
+  }
+
+  getEntries(): AuditEntry[] {
+    return [...this.entries];
+  }
+
+  getEntriesForRecipient(recipient: string): AuditEntry[] {
+    return this.entries.filter((e) => e.recipient === recipient);
+  }
+
+  clear(): void {
+    this.entries = [];
+  }
+}

