+/**
+ * Notification preferences service.
+ *
+ * Allows per-user channel preferences that override the default
+ * priority-based routing. For example, a user can opt to receive
+ * all notifications via SMS regardless of priority.
+ */
+
+import type { NotificationPriority } from '../events/event-types.js';
+
+export interface UserChannelPreference {
+  /** Override channel for a specific priority level. */
+  priority: NotificationPriority;
+  /** The channel the user prefers for this priority. */
+  channel: string;
+}
+
+export class NotificationPreferencesService {
+  /** Map of userId → array of per-priority channel overrides. */
+  private preferences: Map<string, UserChannelPreference[]> = new Map();
+
+  /**
+   * Set a user's preferred channel for a given priority level.
+   */
+  setPreference(userId: string, priority: NotificationPriority, channel: string): void {
+    const existing = this.preferences.get(userId) ?? [];
+    const idx = existing.findIndex((p) => p.priority === priority);
+    if (idx >= 0) {
+      existing[idx] = { priority, channel };
+    } else {
+      existing.push({ priority, channel });
+    }
+    this.preferences.set(userId, existing);
+  }
+
+  /**
+   * Get the user's preferred channel for a priority, or undefined if no override.
+   */
+  getPreferredChannel(userId: string, priority: NotificationPriority): string | undefined {
+    const prefs = this.preferences.get(userId);
+    if (!prefs) return undefined;
+    return prefs.find((p) => p.priority === priority)?.channel;
+  }
+
+  /**
+   * Remove all preferences for a user.
+   */
+  clearPreferences(userId: string): void {
+    this.preferences.delete(userId);
+  }
+
+  /**
+   * Clear all stored preferences (useful for testing).
+   */
+  clearAll(): void {
+    this.preferences.clear();
+  }
+}

