+import type { OrderCreatedEvent } from '../../src/events/event-types.js';
+
+describe('Notification Flow Integration', () => {
+  let eventBus: EventBus;
+  let preferencesService: NotificationPreferencesService;
+  let notificationService: NotificationService;
+  let auditService: AuditService;
+  let emailChannel: EmailNotificationChannel;
+  let smsChannel: SmsNotificationChannel;
+  let webhookChannel: WebhookNotificationChannel;
+
+  beforeEach(() => {
+    eventBus = new EventBus();
+    preferencesService = new NotificationPreferencesService();
+
+    // Audit service must be created before notification service so it
+    // registers its handler first and captures all events.
+    auditService = new AuditService(eventBus);
+    notificationService = new NotificationService(eventBus, preferencesService);
+
+    emailChannel = new EmailNotificationChannel();
+    smsChannel = new SmsNotificationChannel();
+    webhookChannel = new WebhookNotificationChannel();
+
+    notificationService.addChannel(emailChannel);
+    notificationService.addChannel(smsChannel);
+    notificationService.addChannel(webhookChannel);
+
+    resetNotificationIdCounter();
+    resetAuditIdCounter();
+  });
+
+  describe('priority-based routing', () => {
+    it('should route urgent notifications to SMS', async () => {
+      notificationService.sendNotification({
+        channel: new PriorityRouter().resolve('urgent'),
+        priority: 'urgent',
+        recipient: 'alice@example.com',
+        subject: 'Server Down',
+        body: 'Production server is unresponsive.',
+      });
+
+      // Wait for async EventBus processing
+      await eventBus.emit({ type: 'notification:send', channel: 'sms', priority: 'urgent', recipient: '__noop__', subject: '', body: '', timestamp: new Date() });
+
+      const notifications = notificationService.getNotifications();
+      const urgent = notifications.find((n) => n.recipient === 'alice@example.com');
+      expect(urgent).toBeDefined();
+      expect(urgent!.channel).toBe('sms');
+      expect(urgent!.priority).toBe('urgent');
+
+      expect(smsChannel.getSentMessages().some((m) => m.recipient === 'alice@example.com')).toBe(true);
+    });
+
+    it('should route normal notifications to email', async () => {
+      notificationService.sendNotification({
+        channel: new PriorityRouter().resolve('normal'),
+        priority: 'normal',
+        recipient: 'bob@example.com',
+        subject: 'Order Update',
+        body: 'Your order has shipped.',
+      });
+
+      const notifications = notificationService.getNotifications();
+      const normal = notifications.find((n) => n.recipient === 'bob@example.com');
+      expect(normal).toBeDefined();
+      expect(normal!.channel).toBe('email');
+      expect(normal!.priority).toBe('normal');
+
+      expect(emailChannel.getSentEmails().some((e) => e.recipient === 'bob@example.com')).toBe(true);
+    });
+
+    it('should route low-priority notifications to webhook', async () => {
+      notificationService.sendNotification({
+        channel: new PriorityRouter().resolve('low'),
+        priority: 'low',
+        recipient: 'system-hook',
+        subject: 'Daily digest',
+        body: 'Summary of today\'s activity.',
+      });
+
+      const notifications = notificationService.getNotifications();
+      const low = notifications.find((n) => n.recipient === 'system-hook');
+      expect(low).toBeDefined();
+      expect(low!.channel).toBe('webhook');
+      expect(low!.priority).toBe('low');
+
+      expect(webhookChannel.getDeliveredPayloads().some((p) => p.recipient === 'system-hook')).toBe(true);
+    });
+
+    it('should default order:created events to normal priority (email)', async () => {
+      const event: OrderCreatedEvent = {
+        type: 'order:created',
+        order: {
+          id: 'order-1',
+          userId: 'user-1',
+          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
