/**
 * Priority-based notification router.
 *
 * Maps notification priority levels to delivery channels:
 * - urgent → sms
 * - normal → email
 * - low → webhook
 */

import type { NotificationPriority } from '../events/event-types.js';

const PRIORITY_CHANNEL_MAP: Record<NotificationPriority, string> = {
  urgent: 'sms',
  normal: 'email',
  low: 'webhook',
};

export class PriorityRouter {
  /**
   * Resolve the delivery channel for a given priority level.
   */
  resolve(priority: NotificationPriority): string {
    return PRIORITY_CHANNEL_MAP[priority];
  }
}

/**
 * Audit logging service for notifications.
 *
 * Records every notification dispatched through the system. Listens to
 * notification:send events on the EventBus and creates an audit trail.
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationPriority, NotificationSendEvent } from '../events/event-types.js';

export interface AuditEntry {
  id: string;
  timestamp: Date;
  channel: string;
  priority: NotificationPriority;
  recipient: string;
  subject: string;
}

let nextAuditId = 1;

function generateAuditId(): string {
  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
}

export function resetAuditIdCounter(): void {
  nextAuditId = 1;
}

export class AuditService {
  private entries: AuditEntry[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationSendEvent>('notification:send', (event) => {
      this.record(event);
    });
  }

  private record(event: NotificationSendEvent): void {
    this.entries.push({
      id: generateAuditId(),
      timestamp: event.timestamp,
      channel: event.channel,
      priority: event.priority,
      recipient: event.recipient,
      subject: event.subject,
    });
  }

  getEntries(): AuditEntry[] {
    return [...this.entries];
  }

  getEntriesForRecipient(recipient: string): AuditEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  clear(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service.
 *
 * Allows per-user channel preferences that override the default
 * priority-based routing. For example, a user can opt to receive
 * all notifications via SMS regardless of priority.
 */

import type { NotificationPriority } from '../events/event-types.js';

export interface UserChannelPreference {
  /** Override channel for a specific priority level. */
  priority: NotificationPriority;
  /** The channel the user prefers for this priority. */
  channel: string;
}

export class NotificationPreferencesService {
  /** Map of userId → array of per-priority channel overrides. */
  private preferences: Map<string, UserChannelPreference[]> = new Map();

  /**
   * Set a user's preferred channel for a given priority level.
   */
  setPreference(userId: string, priority: NotificationPriority, channel: string): void {
    const existing = this.preferences.get(userId) ?? [];
    const idx = existing.findIndex((p) => p.priority === priority);
    if (idx >= 0) {
      existing[idx] = { priority, channel };
    } else {
      existing.push({ priority, channel });
    }
    this.preferences.set(userId, existing);
  }

  /**
   * Get the user's preferred channel for a priority, or undefined if no override.
   */
  getPreferredChannel(userId: string, priority: NotificationPriority): string | undefined {
    const prefs = this.preferences.get(userId);
    if (!prefs) return undefined;
    return prefs.find((p) => p.priority === priority)?.channel;
  }

  /**
   * Remove all preferences for a user.
   */
  clearPreferences(userId: string): void {
    this.preferences.delete(userId);
  }

  /**
   * Clear all stored preferences (useful for testing).
   */
  clearAll(): void {
    this.preferences.clear();
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * Uses the EventBus pattern throughout:
 * 1. Listens for domain events (order:created, order:status-changed)
 * 2. Uses PriorityRouter to determine default channel based on priority
 * 3. Checks NotificationPreferencesService for per-user overrides
 * 4. Publishes notification:send events for channel handlers to deliver
 *
 * Channel handlers (email, SMS, etc.) subscribe to notification:send events
 * and handle delivery for their respective channel. This makes the system
 * extensible — new channels can be added without modifying this service.
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events and dispatching to channels
 * - PriorityRouter for priority-based channel selection
 * - NotificationPreferencesService for per-user channel overrides
 * - NotificationChannel implementations for actual delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  NotificationPriority,
  NotificationSendEvent,
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../events/event-types.js';
import { Logger } from '../utils/logger.js';
import type { NotificationChannel } from './channels/notification-channel.js';
import type { NotificationPreferencesService } from './notification-preferences.service.js';
import { PriorityRouter } from './priority-router.js';

export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  channel: string;
  priority: NotificationPriority;
  sentAt: Date;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private channels: Map<string, NotificationChannel> = new Map();
  private priorityRouter = new PriorityRouter();

  constructor(
    private eventBus: EventBus,
    private preferencesService?: NotificationPreferencesService,
  ) {
    this.registerDomainHandlers();
    this.registerNotificationHandler();
  }

  /**
   * Add a notification channel. The channel will receive notification:send
   * events matching its name via the EventBus.
   */
  addChannel(channel: NotificationChannel): void {
    this.channels.set(channel.name, channel);
    this.logger.info(`Channel registered: ${channel.name}`);
  }

  /**
   * Register handlers for domain events that trigger notifications.
   */
  private registerDomainHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Register handler for notification:send events.
   * Records the notification and delegates to the appropriate channel.
   */
  private registerNotificationHandler(): void {
    this.eventBus.on<NotificationSendEvent>('notification:send', (event) => {
      const notification: Notification = {
        id: generateNotificationId(),
        recipient: event.recipient,
        subject: event.subject,
        body: event.body,
        channel: event.channel,
        priority: event.priority,
        sentAt: new Date(),
      };
      this.notifications.push(notification);

      const channel = this.channels.get(event.channel);
      if (channel) {
        channel.send(event);
      }

      this.logger.info(
        `Notification ${notification.id} sent via ${event.channel} to ${event.recipient} [${event.priority}]`,
      );
    });
  }

  /**
   * Resolve the delivery channel for a notification, considering user
   * preferences and falling back to priority-based routing.
   */
  private resolveChannel(recipient: string, priority: NotificationPriority): string {
    if (this.preferencesService) {
      const preferred = this.preferencesService.getPreferredChannel(recipient, priority);
      if (preferred) {
        return preferred;
      }
    }
    return this.priorityRouter.resolve(priority);
  }

  /**
   * Handle order created event — send confirmation to user.
   * Priority: normal (routes to email by default).
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    const priority: NotificationPriority = 'normal';
    const channel = this.resolveChannel(event.user.email, priority);

    this.sendNotification({
      channel,
      priority,
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  /**
   * Handle order status change — notify user of update.
   * Priority: normal (routes to email by default).
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const priority: NotificationPriority = 'normal';
    const channel = this.resolveChannel(event.order.userId, priority);

    this.sendNotification({
      channel,
      priority,
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  /**
   * Publish a notification:send event to the EventBus.
   * Channel handlers will pick it up and handle delivery.
   */
  sendNotification(params: {
    channel: string;
    priority: NotificationPriority;
    recipient: string;
    subject: string;
    body: string;
  }): void {
    const event: NotificationSendEvent = {
      type: 'notification:send',
      channel: params.channel,
      priority: params.priority,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      timestamp: new Date(),
    };
    void this.eventBus.emit(event);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

