      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]!.channel).toBe('sms');

      // Verify SMS delivery
      const messages = smsChannel.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]!.recipient).toBe('ops@example.com');

      // Verify audit entry
      const audit = auditService.getEntries();
      expect(audit).toHaveLength(1);
      expect(audit[0]!.channel).toBe('sms');
      expect(audit[0]!.priority).toBe('urgent');
      expect(audit[0]!.recipient).toBe('ops@example.com');
