      const channel = preferencesService.getPreferredChannel('custom@example.com', 'urgent') ?? 'sms';

      notificationService.sendNotification({
        channel,
        priority: 'urgent',
        recipient: 'custom@example.com',
        subject: 'Custom Alert',
        body: 'Routed via preference.',
      });

      // Verify preference override
      const notifications = notificationService.getNotifications();
      expect(notifications[0]!.channel).toBe('webhook');

      // Verify webhook delivery
      expect(webhookChannel.getDeliveredPayloads()).toHaveLength(1);
      expect(smsChannel.getSentMessages()).toHaveLength(0);

      // Verify audit
      const audit = auditService.getEntries();
      expect(audit).toHaveLength(1);
      expect(audit[0]!.channel).toBe('webhook');
      expect(audit[0]!.priority).toBe('urgent');
    });

    it('should handle multiple notifications with different priorities', async () => {
      const router = new PriorityRouter();

      notificationService.sendNotification({
        channel: router.resolve('urgent'),
