      expect(notifications).toHaveLength(3);
      expect(notifications[0]!.channel).toBe('sms');
      expect(notifications[1]!.channel).toBe('email');
      expect(notifications[2]!.channel).toBe('webhook');

      // Verify each channel received its message
      expect(smsChannel.getSentMessages()).toHaveLength(1);
      expect(emailChannel.getSentEmails()).toHaveLength(1);
      expect(webhookChannel.getDeliveredPayloads()).toHaveLength(1);

      // Verify audit has all three entries
      const audit = auditService.getEntries();
      expect(audit).toHaveLength(3);
      expect(audit[0]!.priority).toBe('urgent');
      expect(audit[1]!.priority).toBe('normal');
      expect(audit[2]!.priority).toBe('low');
    });
  });
